SELECT ?coachLabel WHERE {
  ?game wdt:P276 ?venue ;
        wdt:P585 ?date ;
        wdt:P170 ?awayTeam ;
        wdt:P171 ?homeTeam .
  ?venue wdt:P131 wd:Q179295 .
  FILTER (YEAR(?date) = 2014)
  ?awayTeam wdt:P1264 wd:Q160881 .
  ?homeTeam wdt:P1264 ?homeConference .
  FILTER (?homeConference IN (wd:Q192082, wd:Q124855, wd:Q181015, wd:Q291202))
  ?awayTeam wdt:P1388 ?coach .
  OPTIONAL { ?coach rdfs:label ?coachLabel FILTER (LANG(?coachLabel) = "en") }
}

